import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []
all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for key in all_keys:
    bv = b.get(key)
    av = a.get(key)
    if bv and av and bv == av:
        unchanged.append(key + (av,))
    elif bv and av and bv != av:
        changes.append(key + (bv, av, 'Aligned to highest version'))
    elif bv and not av:
        changes.append(key + (bv, 'REMOVED', 'Package removed'))
    elif not bv and av:
        changes.append(key + ('N/A', av, 'Package added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]:20s} {c[1]:8s} {c[2]:50s} {c[3]:10s} -> {c[4]:10s} {c[5]}')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]:20s} {u[1]:8s} {u[2]:50s} {u[3]}')
"

